import type { QuickStartTemplateKey } from "@/config/stabilityQuickStartTemplates";

export type RepairMapTriggerKey =
  | "capture_missing_signal"
  | "standardize_operating_rhythm"
  | "tighten_follow_up"
  | "tighten_cash_visibility"
  | "pricing_margin_review"
  | "capacity_review"
  | "training_handoff"
  | "inventory_control"
  | "vendor_review"
  | "customer_experience_review"
  | "channel_concentration_review"
  | "source_of_truth_review";

export interface DepthMetricAdminAnnotation {
  metric_key: string;
  admin_only_note: string;
  repair_trigger: RepairMapTriggerKey;
  source_of_truth_conflict_capable: boolean;
  repair_map_trigger_behavior: "additive_admin_annotation_only";
}

interface ExpansionSeed {
  slug: string;
  label: string;
  gears: ReadonlyArray<DepthGearKey>;
  trigger_rule: string;
  threshold_value: number | null;
  threshold_unit: DepthMetricDefinition["threshold_unit"];
  client_safe_explanation: string;
  evidence_examples: ReadonlyArray<DepthEvidenceSourceType>;
  forward_risk: string;
  repair_map_recommendation: string;
  recommended_quick_start_templates: ReadonlyArray<QuickStartTemplateKey>;
  admin_only_note: string;
  repair_trigger: RepairMapTriggerKey;
  source_of_truth_conflict_capable?: boolean;
}

