const EXPANSION_SEEDS: Record<DepthIndustryKey, ExpansionSeed[]> = {
  general_small_business: GENERAL_EXPANSION,
  restaurant_food_service: RESTAURANT_EXPANSION,
  retail: RETAIL_EXPANSION,
  professional_services: PROFESSIONAL_EXPANSION,
  ecommerce_online_retail: ECOMMERCE_EXPANSION,
};

const PREFIX_BY_INDUSTRY: Record<DepthIndustryKey, string> = {
  general_small_business: "general",
  restaurant_food_service: "restaurant",
  retail: "retail",
  professional_services: "professional",
  ecommerce_online_retail: "ecommerce",
};

function seed(
  slug: string,
  label: string,
  gears: ReadonlyArray<DepthGearKey>,
  trigger_rule: string,
  threshold_value: number | null,
  threshold_unit: DepthMetricDefinition["threshold_unit"],
  client_safe_explanation: string,
  evidence_examples: ReadonlyArray<DepthEvidenceSourceType>,
  forward_risk: string,
  repair_map_recommendation: string,
  recommended_quick_start_templates: ReadonlyArray<QuickStartTemplateKey>,
  admin_only_note: string,
  repair_trigger: RepairMapTriggerKey,
  source_of_truth_conflict_capable = false,
): ExpansionSeed {
  return {
    slug,
    label,
    gears,
    trigger_rule,
    threshold_value,
    threshold_unit,
    client_safe_explanation,
    evidence_examples,
    forward_risk,
    repair_map_recommendation,
    recommended_quick_start_templates,
    admin_only_note,
    repair_trigger,
    source_of_truth_conflict_capable,
  };
}

function metricKey(industry: DepthIndustryKey, slug: string): string {
  return `${PREFIX_BY_INDUSTRY[industry]}.p89.${slug}`;
}

export const INDUSTRY_DEPTH_EXPANSION_METRICS: DepthMetricDefinition[] =
  Object.entries(EXPANSION_SEEDS).flatMap(([industry, seeds]) =>
    seeds.map((s) => ({
      metric_key: metricKey(industry as DepthIndustryKey, s.slug),
      industry_key: industry as DepthIndustryKey,
      label: s.label,
      gears: s.gears,
      trigger_rule: s.trigger_rule,
      threshold_value: s.threshold_value,
      threshold_unit: s.threshold_unit,
      client_safe_explanation: s.client_safe_explanation,
      evidence_examples: s.evidence_examples,
      forward_risk: s.forward_risk,
      repair_map_recommendation: s.repair_map_recommendation,
      recommended_quick_start_templates: s.recommended_quick_start_templates,
    })),
  );

export const INDUSTRY_DEPTH_ADMIN_ANNOTATIONS: DepthMetricAdminAnnotation[] =
  Object.entries(EXPANSION_SEEDS).flatMap(([industry, seeds]) =>
    seeds.map((s) => ({
      metric_key: metricKey(industry as DepthIndustryKey, s.slug),
      admin_only_note: s.admin_only_note,
      repair_trigger: s.repair_trigger,
      source_of_truth_conflict_capable: Boolean(s.source_of_truth_conflict_capable),
      repair_map_trigger_behavior: "additive_admin_annotation_only",
    })),
  );

